 33	// ListArtifacts returns all MET-* artifacts in document ID order.
 34	func (s *Store) ListArtifacts() ([]docgraph.Document, error) {
 35		graph, err := docgraph.BuildGraph(s.WorkingDir)
 36		if err != nil {
 37			return nil, err
 38		}
 39		ids := graph.All()
 40		out := make([]docgraph.Document, 0, len(ids))
 41		for _, id := range ids {
 42			if !strings.HasPrefix(id, "MET-") {
 43				continue
 44			}
 45			doc, ok := graph.Show(id)
 46			if !ok {
 47				continue
 48			}
 49			out = append(out, doc)
 50		}
 51		return out, nil
 52	}
