 54	func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
 55		doc, err := s.loadMetricArtifact(metricID)
 56		if err != nil {
 57			return nil, nil, err
 58		}
 59		def, err := s.LoadDefinition(metricID)
 60		if err != nil {
 61			return nil, nil, err
 62		}
 63		if def.MetricID != metricID {
 64			return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
 65		}
 66		if len(def.Command) == 0 {
 67			return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
 68		}
 69		if def.Comparison == "" {
 70			def.Comparison = ComparisonLowerIsBetter
 71		}
 72		switch def.Comparison {
 73		case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
 74		default:
 75			return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
 76		}
 77		return &def, doc, nil
 78	}
