 80	func (s *Store) Run(ctx context.Context, metricID string) (HistoryRecord, error) {
 81		def, _, err := s.Validate(metricID)
 82		if err != nil {
 83			return HistoryRecord{}, err
 84		}
 85		rec, err := s.execStore.Run(ctx, def.DefinitionID)
 86		if err != nil {
 87			return HistoryRecord{}, err
 88		}
 89		return metricHistoryFromExec(rec)
 90	}
