 92	func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
 93		history, err := s.History(metricID)
 94		if err != nil {
 95			return HistoryRecord{}, ComparisonResult{}, err
 96		}
 97		if len(history) == 0 {
 98			return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
 99		}
100		current := history[len(history)-1]
101		target, err := selectComparisonTarget(history, against)
102		if err != nil {
103			return HistoryRecord{}, ComparisonResult{}, err
104		}
105		result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
106		current.Comparison = result
107		return current, result, nil
108	}
