110	func (s *Store) Trend(metricID string) (TrendSummary, error) {
111		history, err := s.History(metricID)
112		if err != nil {
113			return TrendSummary{}, err
114		}
115		if len(history) == 0 {
116			return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
117		}
118		summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: history[len(history)-1].Unit, UpdatedAt: history[len(history)-1].ObservedAt}
119		var sum float64
120		for _, rec := range history {
121			if rec.Value < summary.Min {
122				summary.Min = rec.Value
123			}
124			if rec.Value > summary.Max {
125				summary.Max = rec.Value
126			}
127			sum += rec.Value
128			summary.UpdatedAt = rec.ObservedAt
129			if rec.Unit != "" {
130				summary.Unit = rec.Unit
131			}
132		}
133		summary.Count = len(history)
134		summary.Average = sum / float64(len(history))
135		return summary, nil
136	}
