138	func (s *Store) LoadDefinition(metricID string) (Definition, error) {
139		if s.execStore == nil {
140			return Definition{}, fmt.Errorf("metric store is not initialized")
141		}
142		defs, err := s.execStore.ListDefinitions(metricID)
143		if err != nil {
144			return Definition{}, err
145		}
146		var (
147			best  Definition
148			found bool
149		)
150		for _, def := range defs {
151			if def.ID == "" {
152				continue
153			}
154			mapped, err := metricDefinitionFromExec(def)
155			if err != nil {
156				return Definition{}, err
157			}
158			if mapped.MetricID != metricID || !mapped.Active {
159				continue
160			}
